from dataclasses import dataclass, field
from typing import Literal

Level = Literal[1, 2, 3, 4, 5]
EvidenceQuality = Literal["Strong", "Moderate", "Weak", "Missing"]

@dataclass
class EvidenceItem:
    dimension: str
    item: str
    quality: EvidenceQuality
    note: str = ""

@dataclass
class DimensionAudit:
    dimension: str
    provisional_score: Level
    evidence: list[EvidenceItem] = field(default_factory=list)
    interviewer_notes: str = ""
    independent_reviewer_score: Level | None = None

    def final_score(self) -> Level:
        if self.independent_reviewer_score is None:
            return self.provisional_score
        # Lower score wins when discrepancy > 1 level
        diff = abs(self.provisional_score - self.independent_reviewer_score)
        if diff > 1:
            return min(self.provisional_score, self.independent_reviewer_score)
        # Within 1 level: average (rounded down)
        return (self.provisional_score + self.independent_reviewer_score) // 2

    def evidence_coverage(self) -> float:
        if not self.evidence:
            return 0.0
        strong_or_moderate = sum(
            1 for e in self.evidence
            if e.quality in ("Strong", "Moderate")
        )
        return strong_or_moderate / len(self.evidence)

# Example
dim = DimensionAudit(
    dimension="data_infrastructure",
    provisional_score=3,
    independent_reviewer_score=2,
    evidence=[
        EvidenceItem("data_infrastructure", "Data catalogue", "Strong", "Collibra deployed, 80% coverage"),
        EvidenceItem("data_infrastructure", "MLOps pipeline", "Moderate", "CI/CD exists but no automated drift detection"),
        EvidenceItem("data_infrastructure", "Feature store", "Missing", "No feature store in place"),
        EvidenceItem("data_infrastructure", "Data quality report", "Weak", "Manual monthly report, not automated"),
    ],
)
print(f"Final score: {dim.final_score()}")  # 2 (lower wins, diff = 1 -> average = 2)
print(f"Evidence coverage: {dim.evidence_coverage():.0%}")  # 50%
